/// Reputation score for an AI agent — updated on each settlement
model AgentReputation {
  /// Unique identifier
  id                   String   @id @default(uuid())
  /// Agent identifier (matches agentId field on invoices)
  agentId              String   @unique
  /// Normalized reputation score 0.0–100.0
  score                Float    @default(0.0)
  /// Tier: "unrated" | "bronze" | "silver" | "gold" | "platinum"
  tier                 String   @default("unrated")
  /// Total invoices successfully settled
  invoicesCompleted    Int      @default(0)
  /// Total invoices disputed or refunded
  invoicesDisputed     Int      @default(0)
  /// Total USDC value settled (sum of amount for SETTLED/COMPLETED invoices)
  totalValueSettled    Float    @default(0.0)
  /// Timestamp of last score recalculation
  lastUpdated          DateTime @default(now())
  createdAt            DateTime @default(now())
  updatedAt            DateTime @updatedAt

  @@index([agentId])
  @@index([tier])
  @@index([score])
}

